export const ps1Games: Game[] = raw.map(([d, t, p, genres, usedP, newP, origP, sales, desc], i) => ({
  id: `ps1-${String(i + 1).padStart(4, "0")}`,
  title: t,
  console_id: "ps1",
  publisher: p,
  developer: p,
  release_date: d,
  original_price: origP,
  genre: genres,
  description: desc,
  player_count: "1-4人",
  current_new_price: newP,
  current_used_price: usedP,
  total_sales: sales,
  premium_rank: usedP !== null && origP !== null ? (usedP > origP * 10 ? 5 : usedP > origP * 5 ? 4 : usedP > origP * 2 ? 3 : usedP > origP ? 2 : 1) : 0,
  slug: slug(t),
}));
